1	//! 配置文件解析模块
2	//!
3	//! 支持从当前目录向上查找 `.codeconnect.toml` 项目配置，
4	//! 并与 `~/.codeconnect/config.toml` 全局配置合并。
5	//!
6	//! 配置涵盖：工作区设置、语言支持、索引策略、搜索参数、
7	//! 复杂度阈值、死代码检测规则和图校验规则。
8	
9	use serde::{Deserialize, Serialize};
10	use std::path::PathBuf;
11	
12	// ============================================================================
13	// CodeConnect 主配置
14	// ============================================================================
15	
16	/// CodeConnect 主配置结构
17	///
18	/// 所有字段都使用 `#[serde(default)]` 以支持部分覆盖，
19	/// 合并时缺失字段使用默认值。
20	#[derive(Debug, Clone, Serialize, Deserialize)]
21	pub struct CodeConnectConfig {
22	    /// 工作区配置
23	    #[serde(default)]
24	    pub workspace: WorkspaceConfig,
25	
26	    /// 语言支持配置
27	    #[serde(default)]
28	    pub languages: LanguagesConfig,
29	
30	    /// 索引配置
31	    #[serde(default)]
32	    pub index: IndexConfig,
33	
34	    /// 搜索配置
35	    #[serde(default)]
36	    pub search: SearchConfig,
37	
38	    /// 复杂度阈值配置
39	    #[serde(default)]
40	    pub complexity: ComplexityConfig,
41	
42	    /// 死代码检测规则
43	    #[serde(default)]
44	    pub dead_code: Vec<DeadCodeConfig>,
45	
46	    /// 图校验规则
47	    #[serde(default)]
48	    pub rules: Vec<RuleConfig>,
49	}
50	
51	impl Default for CodeConnectConfig {
52	    fn default() -> Self {
53	        Self {
54	            workspace: WorkspaceConfig::default(),
55	            languages: LanguagesConfig::default(),
56	            index: IndexConfig::default(),
57	            search: SearchConfig::default(),
58	            complexity: ComplexityConfig::default(),
59	            dead_code: Vec::new(),
60	            rules: Vec::new(),
61	        }
62	    }
63	}
64	
65	// ============================================================================
66	// 工作区配置
67	// ============================================================================
68	
69	/// 工作区配置
70	#[derive(Debug, Clone, Serialize, Deserialize)]
71	pub struct WorkspaceConfig {
72	    /// 项目根目录列表（支持 monorepo）
73	    #[serde(default)]
74	    pub roots: Vec<PathBuf>,
75	
76	    /// 排除的目录模式（glob 格式）
77	    #[serde(default)]
78	    pub excludes: Vec<String>,
79	}
80	
81	impl Default for WorkspaceConfig {
82	    fn default() -> Self {
83	        Self {
84	            roots: vec![PathBuf::from(".")],
85	            excludes: vec![
86	                "**/node_modules/**".into(),
87	                "**/target/**".into(),
88	                "**/build/**".into(),
89	                "**/dist/**".into(),
90	                "**/.git/**".into(),
91	                "**/vendor/**".into(),
92	            ],
93	        }
94	    }
95	}
96	
97	// ============================================================================
98	// 语言配置
99	// ============================================================================
100	
101	/// 各语言开关配置
102	#[derive(Debug, Clone, Serialize, Deserialize)]
103	pub struct LanguagesConfig {
104	    /// Rust 语言支持
105	    #[serde(default = "default_true")]
106	    pub rust: bool,
107	
108	    /// TypeScript 语言支持
109	    #[serde(default = "default_true")]
110	    pub typescript: bool,
111	
112	    /// JavaScript 语言支持
113	    #[serde(default = "default_true")]
114	    pub javascript: bool,
115	
116	    /// Java 语言支持
117	    #[serde(default)]
118	    pub java: bool,
119	
120	    /// Kotlin 语言支持
121	    #[serde(default)]
122	    pub kotlin: bool,
123	
124	    /// C# 语言支持
125	    #[serde(default)]
126	    pub csharp: bool,
127	}
128	
129	fn default_true() -> bool {
130	    true
131	}
132	
133	impl Default for LanguagesConfig {
134	    fn default() -> Self {
135	        Self {
136	            rust: true,
137	            typescript: true,
138	            javascript: true,
139	            java: false,
140	            kotlin: false,
141	            csharp: false,
142	        }
143	    }
144	}
145	
146	// ============================================================================
147	// 索引配置
148	// ============================================================================
149	
150	/// 索引配置
151	#[derive(Debug, Clone, Serialize, Deserialize)]
152	pub struct IndexConfig {
153	    /// 索引数据存储目录（相对于项目根目录），默认 `.codeconnect/`
154	    #[serde(default = "default_data_dir")]
155	    pub data_dir: PathBuf,
156	
157	    /// 是否启用增量索引
158	    #[serde(default = "default_true")]
159	    pub incremental: bool,
160	}
161	
162	fn default_data_dir() -> PathBuf {
163	    PathBuf::from(".codeconnect")
164	}
165	
166	impl Default for IndexConfig {
167	    fn default() -> Self {
168	        Self {
169	            data_dir: default_data_dir(),
170	            incremental: true,
171	        }
172	    }
173	}
174	
175	// ============================================================================
176	// 搜索配置
177	// ============================================================================
178	
179	/// 搜索配置
180	#[derive(Debug, Clone, Serialize, Deserialize)]
181	pub struct SearchConfig {
182	    /// 单次搜索最大返回结果数
183	    #[serde(default = "default_max_results")]
184	    pub max_results: usize,
185	}
186	
187	fn default_max_results() -> usize {
188	    100
189	}
190	
191	impl Default for SearchConfig {
192	    fn default() -> Self {
193	        Self {
194	            max_results: default_max_results(),
195	        }
196	    }
197	}
198	
199	// ============================================================================
200	// 复杂度配置
201	// ============================================================================
202	
203	/// 圈复杂度阈值配置
204	#[derive(Debug, Clone, Serialize, Deserialize)]
205	pub struct ComplexityConfig {
206	    /// 警告阈值（超过此值产生警告）
207	    #[serde(default = "default_warning_threshold")]
208	    pub warning_threshold: u64,
209	
210	    /// 错误阈值（超过此值视为代码质量问题）
211	    #[serde(default = "default_error_threshold")]
212	    pub error_threshold: u64,
213	}
214	
215	fn default_warning_threshold() -> u64 {
216	    15
217	}
218	
219	fn default_error_threshold() -> u64 {
220	    30
221	}
222	
223	impl Default for ComplexityConfig {
224	    fn default() -> Self {
225	        Self {
226	            warning_threshold: default_warning_threshold(),
227	            error_threshold: default_error_threshold(),
228	        }
229	    }
230	}
231	
232	// ============================================================================
233	// 死代码检测配置
234	// ============================================================================
235	
236	/// 死代码检测配置
237	///
238	/// 定义从给定的入口点出发无法到达的代码为"死代码"。
239	#[derive(Debug, Clone, Serialize, Deserialize)]
240	pub struct DeadCodeConfig {
241	    /// 入口点符号名称列表
242	    pub entry_points: Vec<String>,
243	}
244	
245	// ============================================================================
246	// 图校验规则
247	// ============================================================================
248	
249	/// 架构层校验规则
250	///
251	/// 定义哪些层之间允许相互依赖，用于检测架构违规。
252	#[derive(Debug, Clone, Serialize, Deserialize)]
253	pub struct RuleConfig {
254	    /// 规则名称
255	    pub name: String,
256	
257	    /// 规则描述
258	    pub description: String,
259	
260	    /// 参与规则的层名称列表
261	    pub layers: Vec<String>,
262	
263	    /// 允许的依赖方向（"layerA -> layerB" 格式）
264	    pub allowed: Vec<String>,
265	}
266	
267	// ============================================================================
268	// 配置加载函数
269	// ============================================================================
270	
271	/// 加载配置
272	///
273	/// 从当前目录开始向上查找 `.codeconnect.toml`，找到后读取。
274	/// 同时尝试读取 `~/.codeconnect/config.toml` 作为全局配置基准，
275	/// 项目配置会覆盖全局配置。
276	///
277	/// 如果找不到任何配置文件，返回默认配置。
278	pub fn load_config() -> CodeConnectConfig {
279	    let mut config = load_global_config();
280	
281	    // 从当前目录向上查找项目配置
282	    if let Some(project_config) = find_and_load_project_config() {
283	        merge_configs(&mut config, project_config);
284	    }
285	
286	    config
287	}
288	
289	/// 加载全局配置文件 `~/.codeconnect/config.toml`
290	fn load_global_config() -> CodeConnectConfig {
291	    let global_path = dirs_home().join(".codeconnect").join("config.toml");
292	
293	    match std::fs::read_to_string(&global_path) {
294	        Ok(content) => toml::from_str(&content).unwrap_or_default(),
295	        Err(_) => CodeConnectConfig::default(),
296	    }
297	}
298	
299	/// 从当前目录向上查找并加载 `.codeconnect.toml`
300	fn find_and_load_project_config() -> Option<CodeConnectConfig> {
301	    let current_dir = std::env::current_dir().ok()?;
302	    let mut dir = current_dir.as_path();
303	
304	    loop {
305	        let config_path = dir.join(".codeconnect.toml");
306	        if config_path.is_file() {
307	            if let Ok(content) = std::fs::read_to_string(&config_path) {
308	                if let Ok(config) = toml::from_str::<CodeConnectConfig>(&content) {
309	                    return Some(config);
310	                }
311	            }
312	        }
313	
314	        // 向上一级目录
315	        match dir.parent() {
316	            Some(parent) => dir = parent,
317	            None => break,
318	        }
319	    }
320	
321	    None
322	}
323	
324	/// 将项目配置合并到基准配置中（项目配置覆盖全局配置）
325	fn merge_configs(base: &mut CodeConnectConfig, overlay: CodeConnectConfig) {
326	    // 工作区配置：合并 roots 和 excludes
327	    if !overlay.workspace.roots.is_empty() {
328	        base.workspace.roots = overlay.workspace.roots;
329	    }
330	    if !overlay.workspace.excludes.is_empty() {
331	        base.workspace.excludes = overlay.workspace.excludes;
332	    }
333	
334	    // 语言配置：逐字段覆盖
335	    base.languages.rust = overlay.languages.rust;
336	    base.languages.typescript = overlay.languages.typescript;
337	    base.languages.javascript = overlay.languages.javascript;
338	    base.languages.java = overlay.languages.java;
339	    base.languages.kotlin = overlay.languages.kotlin;
340	    base.languages.csharp = overlay.languages.csharp;
341	
342	    // 索引配置
343	    if overlay.index.data_dir != default_data_dir() {
344	        base.index.data_dir = overlay.index.data_dir;
345	    }
346	    base.index.incremental = overlay.index.incremental;
347	
348	    // 搜索配置
349	    base.search.max_results = overlay.search.max_results;
350	
351	    // 复杂度配置
352	    base.complexity.warning_threshold = overlay.complexity.warning_threshold;
353	    base.complexity.error_threshold = overlay.complexity.error_threshold;
354	
355	    // 死代码规则：如果项目配置了，完全替换
356	    if !overlay.dead_code.is_empty() {
357	        base.dead_code = overlay.dead_code;
358	    }
359	
360	    // 校验规则：如果项目配置了，完全替换
361	    if !overlay.rules.is_empty() {
362	        base.rules = overlay.rules;
363	    }
364	}
365	
366	/// 获取用户主目录
367	fn dirs_home() -> PathBuf {
368	    #[cfg(target_os = "windows")]
369	    {
370	        std::env::var("USERPROFILE")
371	            .map(PathBuf::from)
372	            .unwrap_or_else(|_| PathBuf::from("."))
373	    }
374	    #[cfg(not(target_os = "windows"))]
375	    {
376	        std::env::var("HOME")
377	            .map(PathBuf::from)
378	            .unwrap_or_else(|_| PathBuf::from("."))
379	    }
380	}
