386	#[cfg(test)]
387	mod tests {
388	    use super::*;
389	
390	    #[test]
391	    fn test_default_config() {
392	        let config = CodeConnectConfig::default();
393	        assert_eq!(config.workspace.roots.len(), 1);
394	        assert!(config.languages.rust);
395	        assert!(!config.languages.java);
396	        assert!(config.index.incremental);
397	        assert_eq!(config.search.max_results, 100);
398	        assert_eq!(config.complexity.warning_threshold, 15);
399	        assert_eq!(config.complexity.error_threshold, 30);
400	        assert!(config.dead_code.is_empty());
401	        assert!(config.rules.is_empty());
402	    }
403	
404	    #[test]
405	    fn test_languages_config_default() {
406	        let config = LanguagesConfig::default();
407	        assert!(config.rust);
408	        assert!(config.typescript);
409	        assert!(config.javascript);
410	        assert!(!config.java);
411	        assert!(!config.kotlin);
412	        assert!(!config.csharp);
413	    }
414	
415	    #[test]
416	    fn test_workspace_config_default() {
417	        let config = WorkspaceConfig::default();
418	        assert_eq!(config.roots, vec![PathBuf::from(".")]);
419	        assert!(!config.excludes.is_empty());
420	    }
421	}
