426	// 并行解析辅助函数
427	// ============================================================================
428	
429	/// 解析单个文件并提取所有结构化信息
430	///
431	/// 此函数设计为可在 rayon 并行迭代中调用，无外部可变依赖。
432	/// 所有数据通过返回值传递，由主线程统一写入存储。
433	fn parse_single_file(
434	    file_path: &Path,
435	    parser_registry: &Arc<ParserRegistry>,
436	    project_root: &Path,
437	) -> Result<ParsedFile, String> {
438	    // 查找对应的解析器
439	    let parser = parser_registry
440	        .get_for_file(file_path)
441	        .ok_or_else(|| format!("不支持的文件类型: {}", file_path.display()))?;
442	
443	    let language: &'static str = parser.language();
444	
445	    // 读取文件内容
446	    let source = std::fs::read_to_string(file_path)
447	        .map_err(|e| format!("读取文件失败 {}: {}", file_path.display(), e))?;
448	
449	    // 计算内容哈希（blake3::Hash 实现了 Display，输出十六进制字符串）
450	    let content_hash = blake3::hash(source.as_bytes()).to_string();
451	
452	    // 计算相对于项目根目录的路径
453	    let relative_path = file_path
454	        .strip_prefix(project_root)
455	        .unwrap_or(file_path)
456	        .to_string_lossy()
457	        .to_string();
458	
459	    // 解析源码为 AST
460	    let tree = parser
461	        .parse(&source)
462	        .map_err(|e| format!("解析失败 {}: {}", file_path.display(), e))?;
463	
464	    // 提取符号
465	    let symbols = parser.extract_symbols(&tree, &source, file_path);
466	
467	    // 提取调用
468	    let calls = parser.extract_calls(&tree, &source, file_path);
469	
470	    // 提取导入
471	    let imports = parser.extract_imports(&tree, &source, file_path);
472	
473	    let stats = FileIndexStats {
474	        symbols: symbols.len() as u64,
475	        calls: calls.len() as u64,
476	        imports: imports.len() as u64,
477	    };
478	
479	    Ok(ParsedFile {
480	        relative_path,
481	        content_hash,
482	        language,
483	        symbols,
484	        calls,
485	        imports,
486	        stats,
487	    })
488	}
