16	/// 代码质量指标
17	///
18	/// 汇总单个符号的复杂度、耦合度、继承深度等指标。
19	#[derive(Debug, Clone)]
20	pub struct CodeMetrics {
21	    /// 符号唯一 ID
22	    pub symbol_id: String,
23	    /// 符号名称
24	    pub name: String,
25	    /// 圈复杂度（基于分支节点统计）
26	    pub cyclomatic_complexity: u64,
27	    /// 入度（被其他符号调用的次数）
28	    pub fan_in: u64,
29	    /// 出度（调用其他符号的次数）
30	    pub fan_out: u64,
31	    /// 继承深度（从当前类型到继承树根的距离）
32	    pub depth_of_inheritance: u64,
33	}
