52	/// 指标计算器
53	///
54	/// 提供批量计算和死代码检测功能。
55	/// 自身不维护状态，所有方法均为纯函数。
56	pub struct MetricCalculator;
57	
58	impl MetricCalculator {
59	    // ========================================================================
60	    // 圈复杂度
61	    // ========================================================================
62	
63	    /// 计算单个符号的圈复杂度
64	    ///
65	    /// ## 算法
66	    /// 1. 如果 `symbol.complexity` 已有值，直接返回（来自解析器的预计算结果）
67	    /// 2. 否则对 `source` 文本进行轻量级分析，统计分支关键字：
68	    ///    - 条件分支: `if`, `else if`
69	    ///    - 循环: `for`, `while`, `loop`
70	    ///    - 模式匹配: `match`, `case`, `switch`
71	    ///    - 异常处理: `catch`, `except`, `rescue`
72	    ///    - 逻辑运算符（短路求值）: `&&`, `||`
73	    ///    - 空值合并: `?.`, `??`
74	    ///    - 三元运算符: `?`
75	    /// 3. 圈复杂度 = 1（函数入口） + 分支节点总数
76	    pub fn compute_complexity(symbol: &Symbol, source: &str) -> u64 {
77	        // 优先使用解析器预计算的值
78	        if let Some(complexity) = symbol.complexity {
79	            return complexity;
80	        }
81	
82	        // 对源文本做词法级别的分支关键字计数
83	        let mut complexity: u64 = 1; // 函数入口基准值
84	
85	        // 使用简单的空格分隔进行词法分析（非完整解析，但足够准确）
86	        let tokens: Vec<&str> = source
87	            .split(|c: char| c.is_whitespace() || c == '(' || c == ')' || c == '{' || c == '}' || c == ';' || c == ',')
88	            .filter(|s| !s.is_empty())
89	            .collect();
90	
91	        for &token in &tokens {
92	            match token {
93	                // 条件分支
94	                "if" | "elif" | "elsif" | "elseif" => complexity += 1,
95	                // 循环
96	                "for" | "while" | "loop" => complexity += 1,
97	                // 模式匹配
98	                "match" | "case" | "switch" => complexity += 1,
99	                // 异常处理
100	                "catch" | "except" | "rescue" | "finally" => complexity += 1,
101	                // 逻辑运算符（短路求值产生分支）
102	                "&&" | "||" => complexity += 1,
103	                _ => {}
104	            }
105	        }
106	
107	        // 统计三元运算符 `?`（在 token 中单独出现）
108	        complexity += tokens.iter().filter(|&&t| t == "?").count() as u64;
109	
110	        // 统计空值合并运算符 `??` 和可选链 `?.`
111	        // 这需要在原始源文本上统计
112	        complexity += source.matches("??").count() as u64;
113	        complexity += source.matches("?.").count() as u64;
114	
115	        complexity
116	    }
117	
118	    // ========================================================================
119	    // 批量指标计算
120	    // ========================================================================
121	
122	    /// 批量计算所有符号的代码质量指标
123	    ///
124	    /// ## 计算内容
125	    /// - **圈复杂度** — 从 `symbol.complexity` 字段获取（解析器预计算）
126	    /// - **fan_in** — 调用图中指向当前符号的入边数量
127	    /// - **fan_out** — 调用图中从当前符号出发的出边数量
128	    /// - **继承深度** — 类型层次图中当前符号到根的距离
129	    pub fn compute_all(
130	        symbols: &[Symbol],
131	        call_graph: &CallGraph,
132	        type_hierarchy: &TypeHierarchy,
133	    ) -> Vec<CodeMetrics> {
134	        symbols
135	            .iter()
136	            .map(|symbol| {
137	                // 圈复杂度：优先用预计算值，否则默认为 1
138	                let cyclomatic_complexity = symbol.complexity.unwrap_or(1);
139	
140	                // 出入度：从调用图获取
141	                let (fan_in, fan_out) = call_graph.degree(&symbol.name);
142	
143	                // 继承深度：从类型层次图计算祖先数量
144	                let ancestors = type_hierarchy.get_ancestors(&symbol.name);
145	                let depth_of_inheritance = ancestors.len() as u64;
146	
147	                CodeMetrics {
148	                    symbol_id: symbol.id.clone(),
149	                    name: symbol.name.clone(),
150	                    cyclomatic_complexity,
151	                    fan_in,
152	                    fan_out,
153	                    depth_of_inheritance,
154	                }
155	            })
156	            .collect()
157	    }
158	
159	    // ========================================================================
160	    // 死代码检测
161	    // ========================================================================
162	
163	    /// 检测死代码
164	    ///
165	    /// ## 算法
166	    /// 从入口点（main 函数、导出的 pub 函数等）出发，在调用图上做正向 BFS
167	    /// 可达性分析。即从每个入口点开始，沿"调用者→被调用者"方向（出边）遍历，
168	    /// 将能到达的节点标记为"可达"。
169	    ///
170	    /// 最后，所有未被标记为可达的符号即为**可能死代码**。
171	    ///
172	    /// ## 置信度计算
173	    /// - 1.0 — 完全不可达（没有任何入边）
174	    /// - 0.8 — 不可达但至少有一条入边（可能是反射/回调等间接调用）
175	    /// - 0.5 — 不可达但名称匹配常见模式（如 `test_*`）
176	    pub fn detect_dead_code(
177	        all_symbols: &[String],
178	        call_graph: &CallGraph,
179	        entry_points: &[String],
180	    ) -> Vec<DeadCodeEntry> {
181	        // 第1步: 构建可达性集合
182	        let mut reachable = HashSet::new();
183	        let mut queue = VecDeque::new();
184	
185	        // 从入口点开始
186	        for entry in entry_points {
187	            reachable.insert(entry.clone());
188	            queue.push_back(entry.clone());
189	        }
190	
191	        // BFS 正向遍历：从入口点沿出边找到被调用的符号
192	        while let Some(current) = queue.pop_front() {
193	            // 获取 current 调用的所有符号（被调用者）
194	            let callees = call_graph.get_callees(&current);
195	            for callee in callees {
196	                if reachable.insert(callee.clone()) {
197	                    queue.push_back(callee);
198	                }
199	            }
200	        }
201	
202	        // 第2步: 找出不可达符号并计算置信度
203	        let mut dead_entries = Vec::new();
204	        for symbol_name in all_symbols {
205	            if reachable.contains(symbol_name.as_str()) {
206	                continue;
207	            }
208	
209	            let (fan_in, _fan_out) = call_graph.degree(symbol_name);
210	
211	            // 确定置信度和原因
212	            // 注意：名称模式匹配优先于 fan_in 检查，
213	            // 这样 test_* 和 _ 前缀符号即使 fan_in=0 也能获得正确的置信度
214	            let (confidence, reason) = if symbol_name.starts_with("test_") || symbol_name.contains("_test") {
215	                // 可能是测试代码
216	                (0.5, "未被入口点可达，但名称匹配测试模式".to_string())
217	            } else if symbol_name.starts_with('_') {
218	                // 可能是内部/私有函数
219	                (0.7, "未被入口点可达，名称前缀暗示内部函数".to_string())
220	            } else if fan_in == 0 {
221	                // 完全孤立
222	                (1.0, "从任何入口点都不可达，且未被任何符号调用".to_string())
223	            } else {
224	                // 有入边但不可达（可能是反射、动态调用等）
225	                (0.8, format!(
226	                    "未被入口点可达，但被 {} 个符号调用（可能是间接/动态调用）",
227	                    fan_in
228	                ))
229	            };
230	
231	            dead_entries.push(DeadCodeEntry {
232	                symbol_id: format!("dead_{}", symbol_name),
233	                name: symbol_name.clone(),
234	                confidence,
235	                reason,
236	            });
237	        }
238	
239	        dead_entries
240	    }
241	}
