//! 文件变更过滤器
//!
//! 提供 .gitignore 规则过滤和文件扩展名过滤，
//! 确保文件监控事件仅处理相关的源代码文件。

use std::path::Path;

/// 支持的源文件扩展名列表
///
/// 覆盖 CodeConnect 支持的所有编程语言：
/// - Rust: `.rs`
/// - TypeScript: `.ts`, `.tsx`
/// - JavaScript: `.js`, `.jsx`, `.mjs`, `.cjs`
/// - Java: `.java`
/// - C#: `.cs`
/// - Kotlin: `.kt`, `.kts`
/// - Python: `.py`
/// - Go: `.go`
pub const SUPPORTED_EXTENSIONS: &[&str] = &[
    "rs", "ts", "tsx", "js", "jsx", "mjs", "cjs",
    "java", "cs", "kt", "kts", "py", "go",
];

/// 判断文件是否应当被监控
///
/// # 检查逻辑
///
/// 1. **扩展名检查** — 文件扩展名必须在 [`SUPPORTED_EXTENSIONS`] 列表中
/// 2. **排除规则检查** — 使用 `ignore::gitignore::Gitignore` 匹配排除模式，
///    匹配到排除模式的文件会被过滤掉
///
/// # 参数
///
/// - `path` — 待检查的文件路径
/// - `excludes` — 排除模式列表（glob 格式，如 `**/node_modules/**`）
///
/// # 返回
///
/// 返回 `true` 表示该文件应当被监控，`false` 表示应当跳过。
pub fn should_watch(path: &Path, excludes: &[String]) -> bool {
    // ---- 第一步：检查扩展名 ----
    let ext = match path.extension().and_then(|e| e.to_str()) {
        Some(ext) => ext,
        None => return false, // 无扩展名的文件直接跳过
    };

    if !SUPPORTED_EXTENSIONS.contains(&ext) {
        return false;
    }

    // ---- 第二步：检查排除规则 ----
    // 使用 ignore crate 的 Gitignore 匹配器
    // 将 exclude 模式列表构造为 Gitignore 对象
    if excludes.is_empty() {
        return true;
    }

    // 构造临时 Gitignore 匹配器
    // GitignoreBuilder 允许从字符串添加模式
    let mut builder = ignore::gitignore::GitignoreBuilder::new("/");
    for exclude in excludes {
        // ignore crate 会自动忽略以 ! 开头的非否定模式时的行为差异，
        // 这里排除模式只支持否定（不支持 re-include）
        let _ = builder.add_line(None, exclude);
    }

    let gitignore = match builder.build() {
        Ok(gi) => gi,
        Err(_) => return true, // 构建失败时保守地允许通过
    };

    // matched 返回 Match::None 表示不匹配（应该被监控）
    // 返回 Match::Ignore 表示匹配到排除规则（应该被过滤）
    !gitignore.matched(path, path.is_dir()).is_ignore()
}

// ============================================================================
// 测试
// ============================================================================

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_should_watch_supported_extensions() {
        // 支持的扩展名应返回 true
        assert!(should_watch(Path::new("src/main.rs"), &[]));
        assert!(should_watch(Path::new("app.ts"), &[]));
        assert!(should_watch(Path::new("component.tsx"), &[]));
        assert!(should_watch(Path::new("lib.js"), &[]));
        assert!(should_watch(Path::new("module.mjs"), &[]));
        assert!(should_watch(Path::new("Foo.java"), &[]));
        assert!(should_watch(Path::new("Bar.cs"), &[]));
        assert!(should_watch(Path::new("foo.py"), &[]));
        assert!(should_watch(Path::new("main.go"), &[]));
    }

    #[test]
    fn test_should_watch_unsupported_extensions() {
        // 不支持的扩展名应返回 false
        assert!(!should_watch(Path::new("README.md"), &[]));
        assert!(!should_watch(Path::new("config.toml"), &[]));
        assert!(!should_watch(Path::new("Makefile"), &[]));
        assert!(!should_watch(Path::new("image.png"), &[]));
    }

    #[test]
    fn test_should_watch_no_extension() {
        // 无扩展名的文件直接返回 false
        assert!(!should_watch(Path::new("Dockerfile"), &[]));
        assert!(!should_watch(Path::new("LICENSE"), &[]));
    }

    #[test]
    fn test_should_watch_with_excludes() {
        // node_modules 内的 .ts 文件应被过滤
        let excludes = vec!["**/node_modules/**".to_string()];
        assert!(!should_watch(
            Path::new("node_modules/react/index.js"),
            &excludes
        ));

        // target 目录内的 .rs 文件应被过滤
        let excludes = vec!["**/target/**".to_string()];
        assert!(!should_watch(Path::new("target/debug/build.rs"), &excludes));

        // 普通源文件应不被过滤
        assert!(should_watch(Path::new("src/main.rs"), &excludes));
    }

    #[test]
    fn test_should_watch_multiple_excludes() {
        let excludes = vec![
            "**/node_modules/**".to_string(),
            "**/target/**".to_string(),
            "**/dist/**".to_string(),
        ];

        assert!(!should_watch(Path::new("node_modules/pkg/index.js"), &excludes));
        assert!(!should_watch(Path::new("target/debug/lib.rs"), &excludes));
        assert!(!should_watch(Path::new("dist/app.js"), &excludes));
        assert!(should_watch(Path::new("src/lib.rs"), &excludes));
    }

    #[test]
    fn test_should_watch_empty_excludes() {
        // 空排除列表，只要是支持的扩展名都应该通过
        assert!(should_watch(Path::new("any/path/main.rs"), &[]));
        assert!(!should_watch(Path::new("any/path/readme.md"), &[]));
    }
}

//! 文件系统监控
//!
//! 基于 notify crate 的跨平台文件系统事件监控，
//! 支持 debounce 去抖和批量事件处理。
//!
//! # 架构
//!
//! - [`FileWatcher`] 封装 `notify::PollWatcher`，在内部事件循环中
//!   接收原始文件变更事件
//! - 事件按 500ms 窗口进行 debounce 合并，同一批次内的所有变更文件
//!   以去重后的路径集合形式通过 tokio channel 发送出去
//! - 使用 `filter::should_watch` 预过滤不相关的事件

use std::collections::HashSet;
use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::time::Duration;

use notify::{Config, Event, EventKind, PollWatcher, RecursiveMode, Watcher};
use tokio::sync::mpsc;

use crate::filter::should_watch;

/// debounce 窗口时长（毫秒）
const DEBOUNCE_MS: u64 = 500;

/// 文件系统监控器
///
/// 封装 notify PollWatcher，负责监控项目目录中的源文件变更，
/// 在 debounce 后批量发送变更文件路径。
///
/// # 使用示例
///
/// ```ignore
/// let (tx, mut rx) = tokio::sync::mpsc::unbounded_channel();
/// let watcher = FileWatcher::new(project_root, excludes)?;
/// watcher.start(tx).await?;
///
/// // 从 rx 接收变更事件
/// while let Some(changed_files) = rx.recv().await {
///     println!("检测到 {} 个文件变更", changed_files.len());
///     // 处理增量索引更新...
/// }
/// ```
pub struct FileWatcher {
    /// 项目根目录
    project_root: PathBuf,
    /// 排除模式列表（glob 格式）
    excludes: Vec<String>,
}

impl FileWatcher {
    /// 创建新的文件监控器
    ///
    /// # 参数
    ///
    /// - `project_root` — 项目根目录路径，所有监控事件路径均以此为基准
    /// - `excludes` — 排除模式列表，用于过滤不需要监控的目录/文件
    pub fn new(project_root: &Path, excludes: Vec<String>) -> Self {
        Self {
            project_root: project_root.to_path_buf(),
            excludes,
        }
    }

    /// 启动异步文件监控
    ///
    /// 此方法会阻塞当前线程（在 notify 事件循环中运行），
    /// 因此调用方应在独立的 tokio 任务中调用它。
    ///
    /// # 参数
    ///
    /// - `tx` — 用于发送 debounce 后变更文件集合的通道
    ///
    /// # 工作流程
    ///
    /// 1. 创建 `PollWatcher` 并递归监控项目根目录
    /// 2. 在事件循环中接收原始 notify 事件
    /// 3. 过滤无关事件（排除不支持的文件、匹配排除规则的文件）
    /// 4. 在 500ms debounce 窗口内收集变更路径
    /// 5. 窗口期满后发送去重后的路径集合
    pub async fn start(
        &self,
        tx: mpsc::UnboundedSender<Vec<PathBuf>>,
    ) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
        let project_root = self.project_root.clone();
        let excludes = Arc::new(self.excludes.clone());

        // 创建 notify PollWatcher
        let config = Config::default()
            .with_poll_interval(Duration::from_secs(2)); // 每 2 秒轮询一次

        let (event_tx, event_rx) = std::sync::mpsc::channel();

        let mut poll_watcher = PollWatcher::new(
            move |res: Result<Event, notify::Error>| {
                if let Ok(event) = res {
                    let _ = event_tx.send(event);
                }
            },
            config,
        )?;

        // 递归监控项目根目录
        poll_watcher.watch(&project_root, RecursiveMode::Recursive)?;

        // --------------------------------------------------------------------
        // Debounce 事件循环（在独立的 tokio 阻塞任务中运行）
        // --------------------------------------------------------------------
        tokio::task::spawn_blocking(move || {
            // 当前 debounce 窗口开始时间
            let mut window_start: Option<std::time::Instant> = None;
            // 当前窗口内收集的变更路径集合
            let mut pending_paths: HashSet<PathBuf> = HashSet::new();

            loop {
                // 计算下次接收事件的超时时间
                let timeout = window_start.map_or(
                    Duration::from_secs(3600), // 初始状态无窗口，长时间等待
                    |start| {
                        let elapsed = start.elapsed();
                        if elapsed >= Duration::from_millis(DEBOUNCE_MS) {
                            Duration::ZERO
                        } else {
                            Duration::from_millis(DEBOUNCE_MS) - elapsed
                        }
                    },
                );

                // 带超时的接收事件
                match event_rx.recv_timeout(timeout) {
                    Ok(event) => {
                        // 处理事件，收集变更路径
                        let changed_paths = extract_changed_paths(&event);

                        for path in changed_paths {
                            // 过滤不相关的文件
                            if should_watch(&path, &excludes) {
                                if window_start.is_none() {
                                    window_start = Some(std::time::Instant::now());
                                }
                                pending_paths.insert(path);
                            }
                        }
                    }
                    Err(std::sync::mpsc::RecvTimeoutError::Timeout) => {
                        // 超时：当前 debounce 窗口期满
                        if let Some(_start) = window_start.take() {
                            if !pending_paths.is_empty() {
                                let batch: Vec<PathBuf> =
                                    pending_paths.drain().collect();
                                tracing::debug!(
                                    "文件监控 debounce 完成，发送 {} 个变更文件",
                                    batch.len()
                                );
                                // 发送到上层处理，忽略通道关闭错误
                                let _ = tx.send(batch);
                            }
                        }
                        // 重置窗口
                        window_start = None;
                    }
                    Err(std::sync::mpsc::RecvTimeoutError::Disconnected) => {
                        // 事件通道断开，停止监控
                        tracing::info!("文件监控事件通道已关闭，停止监控");
                        break;
                    }
                }
            }
        })
        .await
        .map_err(|e| format!("监控任务失败: {}", e))?;

        Ok(())
    }
}

/// 从 notify Event 中提取变更的文件路径集合
///
/// 处理以下事件类型：
/// - **Create** — 新文件创建
/// - **Modify** — 文件内容修改
/// - **Remove** — 文件删除
/// - **Rename** — 文件重命名
///
/// 对于每种事件类型，收集第一个路径（通常为文件自身路径）。
fn extract_changed_paths(event: &Event) -> Vec<PathBuf> {
    let mut paths = Vec::new();

    match event.kind {
        EventKind::Create(_) | EventKind::Modify(_) | EventKind::Remove(_) => {
            for path in &event.paths {
                paths.push(path.clone());
            }
        }
        EventKind::Any | EventKind::Access(_) | EventKind::Other => {
            // 忽略 access 和未分类事件
        }
    }

    paths
}

