//! MCP 服务器创建与启动
//!
//! 基于 rmcp 实现 MCP 服务器，使用 stdio 传输方式。
//!
//! # 架构
//!
//! 使用 `CodeConnectServer` 结构体实现 `ServerHandler` trait，
//! 通过 `#[tool]` 宏标记工具函数，参数使用 `rmcp::handler::server::wrapper::Parameters<T>` 包装。
//!
//! 启动流程：
//! 1. 创建 `CodeConnectServer` 实例（持有索引和数据存储引用）
//! 2. 通过 `serve_server` 启动 stdio MCP 服务

use std::sync::Arc;

use rmcp::handler::server::wrapper::Parameters;
use rmcp::handler::server::ServerHandler;
use rmcp::model::{
    CallToolResult, Implementation, InitializeResult, RawContent, RawTextContent,
    ServerCapabilities,
};
use rmcp::service::{RoleServer, serve_server};
use rmcp::tool;
use serde_json::Value;

use codeconnect_index::sled_store::SledStore;
use codeconnect_index::tantivy_index::TantivyIndex;

use crate::schemas::*;
use crate::tools::{self, ToolRegistry};

/// CodeConnect MCP 服务器
///
/// 实现 `ServerHandler` trait，提供所有 MCP 工具注册和 handler 逻辑。
/// 持有对索引、存储和服务的共享引用。
#[derive(Clone)]
pub struct CodeConnectServer {
    /// 工具注册表
    registry: Arc<ToolRegistry>,
    /// 服务器信息
    server_info: InitializeResult,
}

impl CodeConnectServer {
    /// 创建新的 MCP 服务器实例
    ///
    /// # 参数
    ///
    /// - `registry` — 工具注册表，包含 sled、tantivy 等服务后端
    pub fn new(registry: ToolRegistry) -> Self {
        let server_info = InitializeResult {
            protocol_version: String::new(),
            capabilities: ServerCapabilities::builder().enable_tools().build(),
            server_info: Implementation {
                name: "codeconnect".into(),
                title: Some("CodeConnect — 多语言代码分析 MCP 服务器".into()),
                version: env!("CARGO_PKG_VERSION").into(),
                description: Some("提供符号搜索、调用分析、影响分析、死代码检测、代码质量指标等代码智能分析能力".into()),
                icons: None,
                website_url: None,
            },
            instructions: Some("使用工具名称查询具体的分析能力。常用: search_symbol, trace_callers, analyze_impact".into()),
        };
        Self {
            registry: Arc::new(registry),
            server_info,
        }
    }

    /// 启动 MCP stdio 服务器
    ///
    /// 使用 tokio::io::stdin/stdout 作为传输通道。
    pub async fn start_stdio(self) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
        let transport = (tokio::io::stdin(), tokio::io::stdout());
        serve_server(self, transport).await?;
        Ok(())
    }
}

// ============================================================================
// ServerHandler 实现
// ============================================================================

impl ServerHandler for CodeConnectServer {
    /// 返回服务器能力信息
    fn get_info(&self) -> InitializeResult {
        self.server_info.clone()
    }
}

// ============================================================================
// MCP 工具方法 — 使用 #[tool] 宏
// ============================================================================

/// 定义工具 trait 来组织所有工具函数
#[tool_router]
