1	//! 变更影响分析服务
2	//!
3	//! 基于调用图的 BFS 传播分析，评估符号变更的影响范围。
4	//! 对每个变更符号向上追溯调用者，按距离分类为直接和传递影响。
5	
6	use std::collections::HashSet;
7	
8	use codeconnect_core::error::CodeConnectError;
9	use codeconnect_graph::call_graph::CallGraph;
10	
11	/// 影响等级枚举
12	///
13	/// 根据调用者与变更符号的距离分类影响程度。
14	#[derive(Debug, Clone, PartialEq, Eq)]
15	pub enum ImpactLevel {
16	    /// 直接调用者（距离 = 1）
17	    Direct,
18	    /// 传递调用者（距离 >= 2）
19	    Transitive,
20	}
21	
22	/// 单个受影响的条目
23	///
24	/// 描述某个符号被变更波及的具体信息。
25	#[derive(Debug, Clone)]
26	pub struct ImpactEntry {
27	    /// 受影响的符号 ID
28	    pub symbol_id: String,
29	    /// 受影响的符号名称
30	    pub name: String,
31	    /// 距离变更符号的调用链深度（1 = 直接调用者）
32	    pub distance: usize,
33	    /// 影响等级
34	    pub level: ImpactLevel,
35	    /// 触发此影响的变更符号 ID
36	    pub caused_by: String,
37	}
38	
39	/// 影响分析报告
40	///
41	/// 汇总所有变更符号的影响面分析结果。
42	#[derive(Debug, Clone)]
43	pub struct ImpactReport {
44	    /// 被分析的变更符号 ID 列表
45	    pub changed_symbols: Vec<String>,
46	    /// 直接调用者（距离 = 1）
47	    pub direct_impacts: Vec<ImpactEntry>,
48	    /// 传递调用者（距离 >= 2）
49	    pub transitive_impacts: Vec<ImpactEntry>,
50	    /// 所有受影响的唯一符号 ID 集合
51	    pub all_affected_ids: HashSet<String>,
52	}
53	
54	impl ImpactReport {
55	    /// 创建空的影响报告
56	    fn new(changed_symbols: Vec<String>) -> Self {
57	        Self {
58	            changed_symbols,
59	            direct_impacts: Vec::new(),
60	            transitive_impacts: Vec::new(),
61	            all_affected_ids: HashSet::new(),
62	        }
63	    }
64	
65	    /// 受影响符号总数（去重后）
66	    pub fn total_affected(&self) -> usize {
67	        self.all_affected_ids.len()
68	    }
69	}
70	
71	/// 变更影响分析器
72	///
73	/// 从 sled 存储或已有调用图构建，对一组变更符号执行 BFS 调用者追溯，
74	/// 按距离分类为直接和传递影响，生成结构化的影响分析报告。
75	pub struct ImpactAnalyzer {
76	    /// 调用图实例
77	    graph: CallGraph,
78	    /// BFS 最大深度（默认 5）
79	    max_depth: usize,
80	}
81	
82	impl ImpactAnalyzer {
83	    /// 从 sled 存储构建影响分析器
84	    ///
85	    /// 扫描 sled 中的调用边，构建完整调用图。
86	    ///
87	    /// # 参数
88	    /// - `sled` — 已打开的 sled 数据库实例
89	    /// - `max_depth` — BFS 最大搜索深度
90	    pub fn new(
91	        sled: &codeconnect_index::sled_store::SledStore,
92	        max_depth: usize,
93	    ) -> Result<Self, CodeConnectError> {
94	        let graph = CallGraph::build_from_sled(sled)?;
95	        Ok(Self { graph, max_depth })
96	    }
97	
98	    /// 从已有调用图构建影响分析器
99	    ///
100	    /// # 参数
101	    /// - `graph` — 已构建好的调用图
102	    /// - `max_depth` — BFS 最大搜索深度
103	    pub fn from_graph(graph: CallGraph, max_depth: usize) -> Self {
104	        Self { graph, max_depth }
105	    }
106	
107	    /// 分析变更影响面
108	    ///
109	    /// 对每个变更符号向上追溯调用者（谁调用了它），
110	    /// 将结果按距离分类：
111	    /// - **距离 = 1** → 直接调用者（`ImpactLevel::Direct`）
112	    /// - **距离 >= 2** → 传递调用者（`ImpactLevel::Transitive`）
113	    ///
114	    /// 同一个符号可能被多个变更符号触发，报告中只计入首次发现的记录。
115	    ///
116	    /// # 参数
117	    /// - `changed_symbols` — 变更符号的 ID 列表
118	    ///
119	    /// # 返回
120	    /// 结构化的影响分析报告。
121	    pub fn analyze(&self, changed_symbols: &[String]) -> ImpactReport {
122	        let mut report = ImpactReport::new(changed_symbols.to_vec());
123	
124	        for symbol_id in changed_symbols {
125	            // 向上追溯调用者
126	            let callers = self.graph.trace_callers(symbol_id, self.max_depth);
127	
128	            for caller in callers {
129	                // 去重：同一符号只计入首次发现
130	                if report.all_affected_ids.contains(&caller.symbol_id) {
131	                    continue;
132	                }
133	                report.all_affected_ids.insert(caller.symbol_id.clone());
134	
135	                let entry = ImpactEntry {
136	                    symbol_id: caller.symbol_id.clone(),
137	                    name: caller.name.clone(),
138	                    distance: caller.depth,
139	                    level: if caller.depth == 1 {
140	                        ImpactLevel::Direct
141	                    } else {
142	                        ImpactLevel::Transitive
143	                    },
144	                    caused_by: symbol_id.clone(),
145	                };
146	
147	                if caller.depth == 1 {
148	                    report.direct_impacts.push(entry);
149	                } else {
150	                    report.transitive_impacts.push(entry);
151	                }
152	            }
153	        }
154	
155	        report
156	    }
157	
158	    /// 设置 BFS 搜索的最大深度
159	    pub fn set_max_depth(&mut self, depth: usize) {
160	        self.max_depth = depth;
161	    }
162	}
163	
164	#[cfg(test)]
165	mod tests {
166	    use super::*;
167	
168	    /// 构建测试调用图：A → B → C → D
169	    fn build_test_graph() -> CallGraph {
170	        let mut graph = CallGraph::new();
171	        graph.add_edge_raw("A", "B");
172	        graph.add_edge_raw("B", "C");
173	        graph.add_edge_raw("C", "D");
174	        graph
175	    }
176	
177	    #[test]
178	    fn test_direct_impact() {
179	        let graph = build_test_graph();
180	        let analyzer = ImpactAnalyzer::from_graph(graph, 5);
181	
182	        // 变更 B → 直接影响者 A（直接调用者）
183	        let report = analyzer.analyze(&["B".to_string()]);
184	
185	        assert_eq!(report.direct_impacts.len(), 1);
186	        assert_eq!(report.direct_impacts[0].name, "A");
187	        assert_eq!(report.direct_impacts[0].distance, 1);
188	        assert_eq!(report.transitive_impacts.len(), 0);
189	    }
190	
191	    #[test]
192	    fn test_transitive_impact() {
193	        let graph = build_test_graph();
194	        let analyzer = ImpactAnalyzer::from_graph(graph, 5);
195	
196	        // 变更 D → A,B,C 都是调用者，A 距离3（传递）, B 距离2（传递）, C 距离1（直接）
197	        let report = analyzer.analyze(&["D".to_string()]);
198	
199	        // C 是直接调用者
200	        assert_eq!(report.direct_impacts.len(), 1);
201	        assert!(report.direct_impacts.iter().any(|e| e.name == "C"));
202	
203	        // A 和 B 是传递调用者
204	        assert_eq!(report.transitive_impacts.len(), 2);
205	        let trans_names: Vec<&str> = report.transitive_impacts.iter().map(|e| e.name.as_str()).collect();
206	        assert!(trans_names.contains(&"A"));
207	        assert!(trans_names.contains(&"B"));
208	    }
209	
210	    #[test]
211	    fn test_multiple_changed_symbols() {
212	        let graph = build_test_graph();
213	        let analyzer = ImpactAnalyzer::from_graph(graph, 5);
214	
215	        // 同时变更 B 和 D
216	        let report = analyzer.analyze(&["B".to_string(), "D".to_string()]);
217	
218	        // B 的直接调用者：A
219	        // D 的直接调用者：C
220	        // D 的传递调用者：A, B
221	        // A 被 B 和 D 两个变更都触发，但去重后只出现一次
222	        assert!(report.direct_impacts.iter().any(|e| e.name == "A")); // B 的直接调用者
223	        assert!(report.direct_impacts.iter().any(|e| e.name == "C")); // D 的直接调用者
224	        assert_eq!(report.direct_impacts.len(), 2);
225	
226	        assert!(report.transitive_impacts.iter().any(|e| e.name == "B")); // D 的传递调用者
227	        // A 已在 direct 中发现，不会在 transitive 中重复
228	        assert_eq!(report.transitive_impacts.len(), 1);
229	
230	        // 总共去重后受影响数：A, C, B = 3
231	        assert_eq!(report.total_affected(), 3);
232	    }
233	
234	    #[test]
235	    fn test_empty_changes() {
236	        let graph = build_test_graph();
237	        let analyzer = ImpactAnalyzer::from_graph(graph, 5);
238	
239	        let report = analyzer.analyze(&[]);
240	        assert!(report.direct_impacts.is_empty());
241	        assert!(report.transitive_impacts.is_empty());
242	        assert_eq!(report.total_affected(), 0);
243	    }
244	
245	    #[test]
246	    fn test_max_depth_limit() {
247	        let graph = build_test_graph();
248	        // max_depth = 1，只查找直接调用者
249	        let analyzer = ImpactAnalyzer::from_graph(graph, 1);
250	
251	        // 变更 D，但 max_depth=1 只能找到 C（直接调用者）
252	        let report = analyzer.analyze(&["D".to_string()]);
253	
254	        assert_eq!(report.direct_impacts.len(), 1);
255	        assert_eq!(report.direct_impacts[0].name, "C");
256	        assert_eq!(report.transitive_impacts.len(), 0);
257	    }
258	}
