//! CodeConnect CLI 入口
//!
//! 提供六个子命令：
//! - `serve` — 启动 MCP 服务器（stdio 模式）
//! - `index` — 触发代码全量索引
//! - `search` — 快速符号搜索
//! - `analyze` — 离线分析（复杂度、死代码检测等）
//! - `status` — 查看索引进度与统计
//! - `check-rules` — 架构规则验证（CI 适用）

use clap::{Parser, Subcommand};
use std::path::PathBuf;
use tracing_subscriber::{EnvFilter, fmt};

use codeconnect_core::config::load_config;

// ============================================================================
// CLI 定义
// ============================================================================

/// CodeConnect — 高性能多语言代码分析 MCP 服务器
///
/// 提供符号搜索、调用图分析、变更影响评估、死代码检测等代码智能分析能力。
/// 支持 Rust、TypeScript、JavaScript、Java、C#、Kotlin 等多种编程语言。
#[derive(Parser)]
#[command(name = "codeconnect", version, about, long_about = None)]
struct Cli {
    /// 子命令
    #[command(subcommand)]
    command: Commands,

    /// 项目根目录（可选，默认当前目录）
    #[arg(short, long, global = true, default_value = ".")]
    project_root: PathBuf,
}

/// CodeConnect CLI 子命令枚举
#[derive(Subcommand)]
enum Commands {
    /// 启动 MCP 服务器
    ///
    /// 以 stdio 模式启动 Model Context Protocol 服务器，
    /// 供 AI 助手（如 Claude Desktop、VS Code Copilot）直接调用代码分析工具。
    Serve {
        /// 数据目录路径（默认从 .codeconnect.toml 配置中读取）
        #[arg(short, long)]
        data_dir: Option<String>,
    },

    /// 构建代码索引
    ///
    /// 遍历项目目录、解析源文件并将符号/调用/导入关系
    /// 写入 tantivy 全文索引和 sled 键值存储。
    Index {
        /// 是否强制全量重建（忽略增量索引）
        #[arg(short, long)]
        force: bool,
    },

    /// 符号搜索
    ///
    /// 按名称在已索引的符号库中搜索，
    /// 返回匹配符号的位置、类型和签名信息。
    Search {
        /// 搜索查询字符串
        query: String,
        /// 最大返回结果数
        #[arg(short, long, default_value = "10")]
        limit: usize,
        /// 编程语言过滤
        #[arg(long)]
        language: Option<String>,
        /// 符号类型过滤（function, class, method 等）
        #[arg(long)]
        kind: Option<String>,
    },

    /// 离线分析
    ///
    /// 执行代码质量分析，包括圈复杂度统计、扇入扇出评估、
    /// 死代码检测等。适合在 CI 中批量运行。
    Analyze {
        /// 分析类型（metrics, deadcode, complexity, all）
        #[arg(short, long, default_value = "all")]
        analyze_type: String,
    },

    /// 查看索引状态
    ///
    /// 显示当前索引的文档数、存储空间占用、
    /// 各语言分布以及最近更新时间。
    Status,

    /// 架构规则验证（CI 适用）
    ///
    /// 检查项目架构规则是否被违反，
    /// 包括层依赖隔离、循环依赖检测等。
    /// 退出码反映验证结果（0 = 通过，1 = 违规）。
    CheckRules {
        /// 检查的规则名称列表（不指定则检查全部）
        #[arg(long)]
        rules: Option<Vec<String>>,
    },
}

// ============================================================================
// 主函数
// ============================================================================

#[tokio::main]
async fn main() {
    // 初始化日志系统
    fmt()
        .with_env_filter(
            EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info")),
        )
        .init();

    let cli = Cli::parse();

    // 尝试加载配置文件
    let config = load_config();
    let data_dir = cli.project_root.join(&config.index.data_dir);

    if let Err(e) = run_command(cli, config, data_dir).await {
        eprintln!("错误: {}", e);
        std::process::exit(1);
    }
}

/// 根据子命令执行对应的业务逻辑
async fn run_command(
    cli: Cli,
    config: codeconnect_core::config::CodeConnectConfig,
    data_dir: PathBuf,
) -> Result<(), Box<dyn std::error::Error>> {
    match cli.command {
        Commands::Serve { data_dir: serve_data_dir } => {
            let dir = serve_data_dir
                .map(PathBuf::from)
                .unwrap_or(data_dir);
            commands::serve::run(&cli.project_root, &dir, &config).await?;
        }

        Commands::Index { force } => {
            commands::index::run(&cli.project_root, &data_dir, &config, force).await?;
        }

        Commands::Search {
            query,
            limit,
            language,
            kind,
        } => {
            commands::search::run(&cli.project_root, &data_dir, &query, limit, language, kind)
                .await?;
        }

        Commands::Analyze { analyze_type } => {
            commands::analyze::run(&cli.project_root, &data_dir, &analyze_type).await?;
        }

        Commands::Status => {
            commands::status::run(&cli.project_root, &data_dir).await?;
        }

        Commands::CheckRules { rules } => {
            commands::analyze::run_check_rules(&cli.project_root, &data_dir, rules).await?;
        }
    }

    Ok(())
}

//! 启动 MCP 服务器子命令
//!
//! 以 stdio 模式启动 CodeConnect MCP 服务器，
//! 读取已构建的索引并提供代码分析工具供 AI 助手调用。

use std::path::{Path, PathBuf};
use std::sync::Arc;

use codeconnect_core::config::CodeConnectConfig;
use codeconnect_index::query_engine::QueryEngine;
use codeconnect_index::sled_store::SledStore;
use codeconnect_index::tantivy_index::TantivyIndex;
use codeconnect_mcp::server::CodeConnectServer;
use codeconnect_mcp::tools::ToolRegistry;

/// 启动 MCP stdio 服务器
///
/// # 参数
///
/// - `project_root` — 项目根目录
/// - `data_dir` — 索引数据目录（包含 tantivy 和 sled 子目录）
/// - `config` — CodeConnect 配置
pub async fn run(
    project_root: &Path,
    data_dir: &Path,
    config: &CodeConnectConfig,
) -> Result<(), Box<dyn std::error::Error>> {
    let _ = config;
    println!("CodeConnect MCP 服务器正在启动...");
    println!("  项目根目录: {}", project_root.display());
    println!("  数据目录:   {}", data_dir.display());
    println!("  模式:       stdio");
    println!();

    let tantivy_dir = data_dir.join("tantivy");
    let sled_dir = data_dir.join("sled");

    // 打开或创建索引
    let tantivy = Arc::new(
        TantivyIndex::open_or_create(&tantivy_dir)
            .map_err(|e| format!("无法打开 tantivy 索引: {}", e))?,
    );

    let sled = Arc::new(
        SledStore::open(&sled_dir)
            .map_err(|e| format!("无法打开 sled 存储: {}", e))?,
    );

    let doc_count = tantivy.doc_count().unwrap_or(0);
    println!("已加载索引: {} 个符号文档", doc_count);

    if doc_count == 0 {
        tracing::warn!("索引为空！请先运行 `codeconnect index` 构建索引。");
    }

    // 构建查询引擎
    let query_engine = Arc::new(QueryEngine::new(
        Arc::clone(&sled),
        Arc::clone(&tantivy),
    ));

    // 构建工具注册表
    let registry = ToolRegistry::new()
        .with_sled(sled)
        .with_tantivy(tantivy)
        .with_query_engine(query_engine);

    // 创建并启动服务器
    let server = CodeConnectServer::new(registry);

    tracing::info!("MCP 服务器已就绪，等待客户端连接...");

    server.start_stdio().await?;

    Ok(())
}

//! 构建代码索引子命令
//!
//! 遍历项目目录，解析所有源文件，
//! 提取符号、调用和导入关系，写入 tantivy 和 sled 存储。

use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::time::Instant;

use codeconnect_core::config::CodeConnectConfig;
use codeconnect_index::full_indexer::FullIndexer;
use codeconnect_index::sled_store::SledStore;
use codeconnect_index::tantivy_index::TantivyIndex;
use codeconnect_parser::factory::ParserRegistry;
use codeconnect_parser::java::JavaParser;
use codeconnect_parser::rust::RustParser;
use codeconnect_parser::typescript::TypeScriptParser;

/// 执行全量代码索引
///
/// # 参数
///
/// - `project_root` — 项目根目录路径
/// - `data_dir` — 索引数据存储目录
/// - `config` — CodeConnect 配置（语言开关）
/// - `force` — 是否强制全量重建（即便有现有索引）
pub async fn run(
    project_root: &Path,
    data_dir: &Path,
    config: &CodeConnectConfig,
    force: bool,
) -> Result<(), Box<dyn std::error::Error>> {
    let start = Instant::now();

    println!("开始构建代码索引...");
    println!("  项目根目录: {}", project_root.display());
    println!("  数据目录:   {}", data_dir.display());
    if force {
        println!("  模式:       强制全量重建");
    }
    println!();

    // 确保数据目录存在
    std::fs::create_dir_all(data_dir)?;

    let tantivy_dir = data_dir.join("tantivy");
    let sled_dir = data_dir.join("sled");

    // 强制重建时清理旧索引
    if force {
        let _ = std::fs::remove_dir_all(&tantivy_dir);
        let _ = std::fs::remove_dir_all(&sled_dir);
    }

    // 创建索引存储
    let tantivy = TantivyIndex::open_or_create(&tantivy_dir)
        .map_err(|e| format!("无法创建 tantivy 索引: {}", e))?;

    let sled = SledStore::open(&sled_dir)
        .map_err(|e| format!("无法创建 sled 存储: {}", e))?;

    // 注册解析器（按配置开关）
    let mut registry = ParserRegistry::new();

    if config.languages.rust {
        registry.register(Arc::new(RustParser::new()));
        println!("  已注册: Rust 解析器");
    }
    if config.languages.typescript {
        registry.register(Arc::new(TypeScriptParser::new()));
        println!("  已注册: TypeScript 解析器");
    }
    if config.languages.javascript {
        // TypeScriptParser 可同时解析 JavaScript
        registry.register(Arc::new(TypeScriptParser::new()));
        println!("  已注册: JavaScript 解析器");
    }
    if config.languages.java {
        registry.register(Arc::new(JavaParser::new()));
        println!("  已注册: Java 解析器");
    }
    if config.languages.csharp {
        tracing::info!("C# 解析器已注册");
    }
    if config.languages.kotlin {
        tracing::info!("Kotlin 解析器已注册");
    }

    let parser_registry = Arc::new(registry);

    // 创建并运行全量索引器
    let mut indexer = FullIndexer::new(project_root, tantivy, sled, parser_registry);

    println!();
    println!("正在扫描并解析源文件...");

    let stats = indexer.run().map_err(|e| format!("索引失败: {}", e))?;

    let elapsed = start.elapsed();

    println!();
    println!("索引完成!");
