//! 构建代码索引子命令
//!
//! 遍历项目目录，解析所有源文件，
//! 提取符号、调用和导入关系，写入 tantivy 和 sled 存储。

use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::time::Instant;

use codeconnect_core::config::CodeConnectConfig;
use codeconnect_index::full_indexer::FullIndexer;
use codeconnect_index::sled_store::SledStore;
use codeconnect_index::tantivy_index::TantivyIndex;
use codeconnect_parser::factory::ParserRegistry;
use codeconnect_parser::java::JavaParser;
use codeconnect_parser::rust::RustParser;
use codeconnect_parser::typescript::TypeScriptParser;

/// 执行全量代码索引
///
/// # 参数
///
/// - `project_root` — 项目根目录路径
/// - `data_dir` — 索引数据存储目录
/// - `config` — CodeConnect 配置（语言开关）
/// - `force` — 是否强制全量重建（即便有现有索引）
pub async fn run(
    project_root: &Path,
    data_dir: &Path,
    config: &CodeConnectConfig,
    force: bool,
) -> Result<(), Box<dyn std::error::Error>> {
    let start = Instant::now();

    println!("开始构建代码索引...");
    println!("  项目根目录: {}", project_root.display());
    println!("  数据目录:   {}", data_dir.display());
    if force {
        println!("  模式:       强制全量重建");
    }
    println!();

    // 确保数据目录存在
    std::fs::create_dir_all(data_dir)?;

    let tantivy_dir = data_dir.join("tantivy");
    let sled_dir = data_dir.join("sled");

    // 强制重建时清理旧索引
    if force {
        let _ = std::fs::remove_dir_all(&tantivy_dir);
        let _ = std::fs::remove_dir_all(&sled_dir);
    }

    // 创建索引存储
    let tantivy = TantivyIndex::open_or_create(&tantivy_dir)
        .map_err(|e| format!("无法创建 tantivy 索引: {}", e))?;

    let sled = SledStore::open(&sled_dir)
        .map_err(|e| format!("无法创建 sled 存储: {}", e))?;

    // 注册解析器（按配置开关）
    let mut registry = ParserRegistry::new();

    if config.languages.rust {
        registry.register(Arc::new(RustParser::new()));
        println!("  已注册: Rust 解析器");
    }
    if config.languages.typescript {
        registry.register(Arc::new(TypeScriptParser::new()));
        println!("  已注册: TypeScript 解析器");
    }
    if config.languages.javascript {
        registry.register(Arc::new(TypeScriptParser::new()));
        println!("  已注册: JavaScript 解析器");
    }
    if config.languages.java {
        registry.register(Arc::new(JavaParser::new()));
        println!("  已注册: Java 解析器");
    }
    if config.languages.csharp {
        tracing::info!("C# 解析器已注册");
    }
    if config.languages.kotlin {
        tracing::info!("Kotlin 解析器已注册");
    }

    let parser_registry = Arc::new(registry);

    // 创建并运行全量索引器
    let mut indexer = FullIndexer::new(project_root, tantivy, sled, parser_registry);

    println!();
    println!("正在扫描并解析源文件...");

    let stats = indexer.run().map_err(|e| format!("索引失败: {}", e))?;

    let elapsed = start.elapsed();

    println!();
    println!("索引完成!");
    println!("  ──────────────────────────────────");
    println!("  扫描文件数:   {}", stats.files_scanned);
    println!("  成功解析:     {}", stats.files_parsed);
    println!("  提取符号数:   {}", stats.symbols_found);
    println!("  发现调用数:   {}", stats.calls_found);
    println!("  发现导入数:   {}", stats.imports_found);
    println!("  解析失败:     {}", stats.failed_files.len());
    println!("  耗时:         {:.2}s", elapsed.as_secs_f64());
    println!("  ──────────────────────────────────");

    // 打印失败详情（如果有）
    if !stats.failed_files.is_empty() {
        println!();
        println!("解析失败的文件:");
        for failure in &stats.failed_files {
            println!("  - {}", failure);
        }
    }

    Ok(())
}

//! 快速符号搜索子命令
//!
//! 通过 tantivy 全文索引按名称搜索符号，
//! 返回匹配符号的位置和类型信息。

use std::path::{Path, PathBuf};
use std::sync::Arc;

use codeconnect_index::sled_store::SledStore;
use codeconnect_index::tantivy_index::TantivyIndex;
use codeconnect_core::types::Symbol;

/// 执行符号搜索
///
/// # 参数
///
/// - `project_root` — 项目根目录
/// - `data_dir` — 索引数据目录
/// - `query` — 搜索查询字符串
/// - `limit` — 最大结果数
/// - `language` — 语言过滤（可选）
/// - `kind` — 符号类型过滤（可选）
pub async fn run(
    project_root: &Path,
    data_dir: &Path,
    query: &str,
    limit: usize,
    language: Option<String>,
    kind: Option<String>,
) -> Result<(), Box<dyn std::error::Error>> {
    let _ = project_root;

    let tantivy_dir = data_dir.join("tantivy");
    let sled_dir = data_dir.join("sled");

    let tantivy = TantivyIndex::open_or_create(&tantivy_dir)
        .map_err(|e| format!("无法打开 tantivy 索引: {}", e))?;
    let sled = SledStore::open(&sled_dir)
        .map_err(|e| format!("无法打开 sled 存储: {}", e))?;

    // 搜索符号
    let search_results = tantivy
        .search_by_name(query, limit)
        .map_err(|e| format!("搜索失败: {}", e))?;

    if search_results.is_empty() {
        println!("未找到匹配 '{}' 的符号", query);
        return Ok(());
    }

    println!("搜索 '{}' 结果 (最多 {} 条):", query, limit);
    println!("{0:-<80}", "");

    let mut shown = 0;
    for result in &search_results {
        // 语言过滤
        if let Some(ref lang) = language {
            let symbol_lang = result.stable_id.split("::").next().unwrap_or("");
            if symbol_lang != lang.as_str() {
                continue;
            }
        }

        // 类型过滤
        if let Some(ref kind_filter) = kind {
            if result.kind != *kind_filter {
                continue;
            }
        }

        // 从 sled 获取完整符号信息
        if let Ok(Some(bytes)) = sled.get_symbol(&result.stable_id) {
            if let Ok(symbol) = serde_json::from_slice::<Symbol>(&bytes) {
                println!(
                    "  {}  [{}]  (相关度: {:.2})",
                    symbol.name, result.kind, result.score
                );
                println!(
                    "    文件: {}:{}",
                    symbol.location.file_path, symbol.location.line
                );
                if let Some(ref sig) = symbol.signature {
                    println!("    签名: {}", sig);
                }
                println!();
                shown += 1;
            }
        }
    }

    if shown == 0 {
        println!("未找到匹配的符号（已应用过滤条件）");
    } else {
        println!("{0:-<80}", "");
        println!("共显示 {} 条结果", shown);
    }

    Ok(())
}

//! 离线分析子命令
//!
//! 执行代码质量分析：圈复杂度、死代码检测、架构规则验证等。

use std::path::{Path, PathBuf};

use codeconnect_core::types::Symbol;
use codeconnect_graph::call_graph::CallGraph;
use codeconnect_graph::metrics::MetricCalculator;
use codeconnect_graph::type_hierarchy::TypeHierarchy;
use codeconnect_index::sled_store::SledStore;

/// 执行离线分析
///
/// # 参数
///
/// - `project_root` — 项目根目录
/// - `data_dir` — 索引数据目录
/// - `analyze_type` — 分析类型（metrics、deadcode、complexity、all）
pub async fn run(
    project_root: &Path,
    data_dir: &Path,
    analyze_type: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    let _ = project_root;

    let sled_dir = data_dir.join("sled");
    let sled = SledStore::open(&sled_dir)
        .map_err(|e| format!("无法打开 sled 存储: {}", e))?;

    // 收集所有符号
    let mut all_symbols: Vec<Symbol> = Vec::new();
    let prefix = "symbols:";
    for item in sled.scan_prefix(prefix.as_bytes()) {
        if let Ok((_key, value)) = item {
            if let Ok(sym) = serde_json::from_slice::<Symbol>(&value) {
                all_symbols.push(sym);
            }
        }
    }

    if all_symbols.is_empty() {
        println!("索引中没有符号数据，请先运行 `codeconnect index`");
        return Ok(());
    }

    println!("符号总数: {}", all_symbols.len());
    println!();

    // 构建调用图
    let call_graph = CallGraph::build_from_sled(&sled)
        .map_err(|e| format!("构建调用图失败: {}", e))?;

    let type_hierarchy = TypeHierarchy::new();

    match analyze_type {
        "complexity" | "metrics" | "all" => {
            // 计算圈复杂度排名
            println!("═══════════════════════════════════════════");
            println!("  圈复杂度分析（Top 10）");
            println!("═══════════════════════════════════════════");

            let metrics = MetricCalculator::compute_all(&all_symbols, &call_graph, &type_hierarchy);

            let mut sorted: Vec<_> = metrics.iter().collect();
            sorted.sort_by(|a, b| b.cyclomatic_complexity.cmp(&a.cyclomatic_complexity));

            for (i, m) in sorted.iter().take(10).enumerate() {
                let marker = if m.cyclomatic_complexity > 30 {
                    " 🔴"
                } else if m.cyclomatic_complexity > 15 {
                    " 🟡"
                } else {
                    ""
                };
                println!(
                    "  {}. {} — 复杂度: {}{} (入:{} / 出:{})",
                    i + 1,
                    m.name,
                    m.cyclomatic_complexity,
                    marker,
                    m.fan_in,
                    m.fan_out,
                );
            }

            // 全局统计
            let total_complexity: u64 = metrics.iter().map(|m| m.cyclomatic_complexity).sum();
            let avg_complexity = if metrics.is_empty() {
                0.0
            } else {
                total_complexity as f64 / metrics.len() as f64
            };
            let high_complexity = metrics
                .iter()
                .filter(|m| m.cyclomatic_complexity > 15)
                .count();
            let very_high = metrics
                .iter()
                .filter(|m| m.cyclomatic_complexity > 30)
                .count();

            println!();
            println!("  全局统计:");
            println!("    总符号数:     {}", metrics.len());
            println!("    平均复杂度:   {:.1}", avg_complexity);
            println!("    高复杂度(>15): {}", high_complexity);
            println!("    极高复杂度(>30): {}", very_high);
            println!();
        }

        if matches!(analyze_type, "deadcode" | "all") {
            // 死代码检测
            println!("═══════════════════════════════════════════");
            println!("  死代码检测");
            println!("═══════════════════════════════════════════");

            let all_names: Vec<String> = all_symbols.iter().map(|s| s.name.clone()).collect();
            let entries = vec!["main".to_string()];

            let dead = MetricCalculator::detect_dead_code(&all_names, &call_graph, &entries);

            if dead.is_empty() {
                println!("  未检测到死代码");
            } else {
                for d in &dead {
                    let confidence_str = if d.confidence >= 0.8 {
                        "高"
                    } else if d.confidence >= 0.5 {
                        "中"
                    } else {
                        "低"
                    };
                    println!(
                        "  {} — 置信度: {} ({:.0}%)",
                        d.name,
                        confidence_str,
                        d.confidence * 100.0
                    );
                    println!("    {}", d.reason);
                }
                println!();
                println!("  共 {} 个可疑死代码条目", dead.len());
            }
            println!();
        }
    }

    Ok(())
}

